'chem-polymers': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><defs><style>@keyframes pol_l{0%{transform:translateX(0)}100%{transform:translateX(-60px)}}.pol_chain{animation:pol_l 3s linear infinite}</style></defs><text x="200" y="22" text-anchor="middle" font-size="10" font-weight="bold" fill="var(--text)" font-family="sans-serif">Addition Polymerisation</text><text x="50" y="50" text-anchor="middle" font-size="11" fill="var(--text-dim)" font-family="sans-serif">CH₂=CH₂</text><text x="130" y="50" text-anchor="middle" font-size="9" fill="var(--accent)" font-family="sans-serif">→ many monomers</text><rect x="185" y="38" width="200" height="22" rx="4" fill="var(--surface)" stroke="var(--accent)" stroke-width="1.5" overflow="hidden"/><g class="pol_chain"><text x="200" y="53" font-size="8.5" fill="var(--accent)" font-family="sans-serif">–CH₂–CH₂–CH₂–CH₂–CH₂–CH₂–CH₂–CH₂–</text></g><text x="200" y="82" text-anchor="middle" font-size="9" fill="var(--text-dim)" font-family="sans-serif">ethene monomers → poly(ethene)</text><text x="200" y="95" text-anchor="middle" font-size="8.5" fill="var(--text-dim)" font-family="sans-serif">C=C opens, no atoms lost, one product</text><line x1="20" y1="108" x2="380" y2="108" stroke="var(--border)" stroke-width="1" stroke-dasharray="4,3"/><text x="200" y="125" text-anchor="middle" font-size="10" font-weight="bold" fill="var(--text)" font-family="sans-serif">Condensation Polymerisation</text><text x="200" y="142" text-anchor="middle" font-size="8.5" fill="var(--text-dim)" font-family="sans-serif">Monomers with –OH and –COOH join releasing H₂O</text><rect x="60" y="152" width="80" height="30" rx="4" fill="var(--accent)" fill-opacity=".15" stroke="var(--accent)" stroke-width="1.2"/><text x="100" y="164" text-anchor="middle" font-size="8" fill="var(--text)" font-family="sans-serif">diamine</text><text x="100" y="175" text-anchor="middle" font-size="7" fill="var(--text-dim)" font-family="sans-serif">H₂N–R–NH₂</text><text x="200" y="167" text-anchor="middle" font-size="9" fill="var(--accent)" font-family="sans-serif">+</text><rect x="218" y="152" width="80" height="30" rx="4" fill="var(--border)" fill-opacity=".2" stroke="var(--border)" stroke-width="1.2"/><text x="258" y="164" text-anchor="middle" font-size="8" fill="var(--text)" font-family="sans-serif">diacid</text><text x="258" y="175" text-anchor="middle" font-size="7" fill="var(--text-dim)" font-family="sans-serif">HOOC–R–COOH</text><text x="200" y="200" text-anchor="middle" font-size="8.5" fill="var(--accent)" font-family="sans-serif">→ Nylon (polyamide) + H₂O released</text><text x="200" y="218" text-anchor="middle" font-size="8" fill="var(--text-dim)" font-family="sans-serif">Polyester: –OH + –COOH → ester linkage + H₂O</text><text x="200" y="245" text-anchor="middle" font-size="8" fill="var(--text-dim)" font-family="sans-serif">Non-biodegradable plastics persist in environment for centuries</text><text x="200" y="284" text-anchor="middle" font-size="11" font-weight="bold" fill="var(--text)" font-family="sans-serif">Polymers</text></svg>`,

